10	func mkModel(power int, available, autoRoutable bool) agentlib.ModelInfo {
11		return agentlib.ModelInfo{
12			Power:        power,
13			Available:    available,
14			AutoRoutable: autoRoutable,
15		}
16	}
17	
18	func viable(power int) agentlib.ModelInfo    { return mkModel(power, true, true) }
19	func nonviable(power int) agentlib.ModelInfo { return mkModel(power, false, true) }
