21	func TestLadder_Tiers_DistinctAscending(t *testing.T) {
22		l := NewLadder([]agentlib.ModelInfo{
23			viable(70), viable(50), viable(70), viable(90), viable(50),
24		})
25		got := l.Tiers()
26		want := []int{50, 70, 90}
27		if len(got) != len(want) {
28			t.Fatalf("Tiers len: got %v want %v", got, want)
29		}
30		for i := range want {
31			if got[i] != want[i] {
32				t.Fatalf("Tiers[%d]: got %d want %d (full=%v)", i, got[i], want[i], got)
33			}
34		}
35	}
