37	func TestLadder_IgnoresUnratedModels(t *testing.T) {
38		l := NewLadder([]agentlib.ModelInfo{
39			viable(50),
40			mkModel(0, true, true), // unrated
41			mkModel(-10, true, true),
42			viable(80),
43		})
44		got := l.Tiers()
45		if len(got) != 2 || got[0] != 50 || got[1] != 80 {
46			t.Fatalf("Tiers: got %v want [50 80]", got)
47		}
