50	func TestLadder_Next_AllViable_StepsThroughTiers(t *testing.T) {
51		l := NewLadder([]agentlib.ModelInfo{viable(50), viable(70), viable(90)})
52	
53		cases := []struct {
54			in, want int
55		}{
56			{0, 50},
57			{50, 70},
58			{60, 70}, // strictly greater
59			{70, 90},
60			{89, 90},
61		}
62		for _, tc := range cases {
63			got, err := l.Next(tc.in)
64			if err != nil {
65				t.Fatalf("Next(%d): unexpected err %v", tc.in, err)
66			}
67			if got != tc.want {
68				t.Fatalf("Next(%d): got %d want %d", tc.in, got, tc.want)
69			}
70		}
71	}
