98	func TestLadder_Next_SkipTierReturnsNoViableProviderError(t *testing.T) {
99		// 50 viable, 70 has only non-viable models, 90 viable.
100		l := NewLadder([]agentlib.ModelInfo{
101			viable(50),
102			nonviable(70),
103			viable(90),
104		})
105	
106		floor, err := l.Next(50)
107		if err == nil {
108			t.Fatalf("Next(50): expected NoViableProviderError, got floor=%d nil err", floor)
109		}
110		var nvp *NoViableProviderError
111		if !errors.As(err, &nvp) {
112			t.Fatalf("Next(50): err = %v; want *NoViableProviderError", err)
113		}
114		if nvp.Floor != 70 {
115			t.Fatalf("NoViableProviderError.Floor: got %d want 70", nvp.Floor)
116		}
117	
118		// Loop bumps further by calling Next(floor=70).
119		got, err := l.Next(nvp.Floor)
120		if err != nil {
121			t.Fatalf("Next(70) after skip: unexpected err %v", err)
122		}
